class Solution:
    def getImportance(self, employees, id):
        # employees is a list of [eid, importance, subordinates]
        lookup = {e[0]: e for e in employees}
        total = 0
        stack = [id]
        while stack:
            eid = stack.pop()
            emp = lookup[eid]
            total += emp[1]
            stack.extend(emp[2])
        return total

