var GetImportance = function(employees, id) {
    const lookup = new Map();
    for (const e of employees) lookup.set(e[0], e);
    let total = 0;
    const queue = [id];
    while (queue.length > 0) {
        const eid = queue.shift();
        const emp = lookup.get(eid);
        total += emp[1];
        for (const sub of emp[2]) queue.push(sub);
    }
    return total;
};
